        self.date = Date()
        self.transactionType = transactionType
    }
}

class BankService {
    private var accounts: [Account] = []
    
    func createAccount(accountNumber: String, initialBalance: Double) {
        let newAccount = Account(accountNumber: accountNumber, balance: initialBalance)
        accounts.append(newAccount)
    }
    
    func getAccountBalance(accountNumber: String) -> Double? {
        return accounts.first { $0.accountNumber == accountNumber }?.balance
    }
    
    func processTransaction(accountNumber: String, amount: Double, transactionType: String) -> Bool {
        if let account = accounts.first(where: { $0.accountNumber == accountNumber }) {
            if transactionType == "deposit" {
                account.deposit(amount: amount)
                return true
            } else if transactionType == "withdraw" {
                return account.withdraw(amount: amount)
            }
        }
        return false
    }
}

